Here's a minimal API endpoint that handles multipart form uploads with multiple images and a description:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(o =>
    o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a multipart form request
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart form request.");

    var form = await request.ReadFormAsync();

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images"); // matches <input name="images">

    if (files.Count == 0)
        return Results.BadRequest("No images uploaded.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        // Validate content type
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var destPath = Path.Combine("uploads", $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}");
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(destPath);
        await file.CopyToAsync(stream);

        saved.Add(destPath);
    }

    return Results.Ok(new { description, fileCount = saved.Count, paths = saved });
})
.DisableAntiforgery()                       // required for minimal APIs accepting forms without a token
.Accepts<IFormFile>("multipart/form-data");

app.Run();
```

**Key points:**

- **`MaxRequestBodySize`** — Kestrel defaults to ~30 MB; set it to 50 MB explicitly.
- **`ReadFormAsync`** — gives you both the text fields and files from one multipart body.
- **`DisableAntiforgery()`** — without this, POST of form data will be rejected by default in .NET 8.
- **Client side**, the form needs `enctype="multipart/form-data"`, with `<input type="file" name="images" multiple>` and `<input type="text" name="description">`.

If you prefer a **typed model** instead of reading `HttpRequest` directly:

```csharp
app.MapPost("/upload-typed", async ([AsParameters] UploadRequest req) =>
{
    // req.Description and req.Images are bound automatically
    return Results.Ok(new { req.Description, count = req.Images?.Count });
})
.DisableAntiforgery();

public class UploadRequest
{
    [FromForm] public string Description { get; set; } = "";
    [FromForm] public IFormFileCollection Images { get; set; } = default!;
}
```
